/* --- genom_bayes_opt_activity_report ---------------------------------- */

void
genom_bayes_opt_activity_report(
  struct genom_component_data *self, struct genom_activity *a)
{
  switch(a->sid) {
    case -1: return; /* permanent activity reports nothing */

    case BAYES_OPT_abort_activity_RQSTID:
      genom_bayes_opt_abort_activity_activity_report(
        self, (struct genom_bayes_opt_abort_activity_activity *)a);
      return;
    case BAYES_OPT_connect_port_RQSTID:
      genom_bayes_opt_connect_port_activity_report(
        self, (struct genom_bayes_opt_connect_port_activity *)a);
      return;
    case BAYES_OPT_connect_service_RQSTID:
      genom_bayes_opt_connect_service_activity_report(
        self, (struct genom_bayes_opt_connect_service_activity *)a);
      return;
    case BAYES_OPT_kill_RQSTID:
      genom_bayes_opt_kill_activity_report(
        self, (struct genom_bayes_opt_kill_activity *)a);
      return;
    case BAYES_OPT_initialize_optimizer_RQSTID:
      genom_bayes_opt_initialize_optimizer_activity_report(
        self, (struct genom_bayes_opt_initialize_optimizer_activity *)a);
      return;
    case BAYES_OPT_propose_parameters_RQSTID:
      genom_bayes_opt_propose_parameters_activity_report(
        self, (struct genom_bayes_opt_propose_parameters_activity *)a);
      return;
    case BAYES_OPT_submit_result_RQSTID:
      genom_bayes_opt_submit_result_activity_report(
        self, (struct genom_bayes_opt_submit_result_activity *)a);
      return;
    case BAYES_OPT_get_best_parameters_RQSTID:
      genom_bayes_opt_get_best_parameters_activity_report(
        self, (struct genom_bayes_opt_get_best_parameters_activity *)a);
      return;
    case BAYES_OPT_reset_optimizer_RQSTID:
      genom_bayes_opt_reset_optimizer_activity_report(
        self, (struct genom_bayes_opt_reset_optimizer_activity *)a);
      return;
    case BAYES_OPT_Init_RQSTID:
      genom_bayes_opt_Init_activity_report(
        self, (struct genom_bayes_opt_Init_activity *)a);
      return;
    case BAYES_OPT_AskNext_RQSTID:
      genom_bayes_opt_AskNext_activity_report(
        self, (struct genom_bayes_opt_AskNext_activity *)a);
      return;
    case BAYES_OPT_SubmitResult_RQSTID:
      genom_bayes_opt_SubmitResult_activity_report(
        self, (struct genom_bayes_opt_SubmitResult_activity *)a);
      return;
    case BAYES_OPT_GetBest_RQSTID:
      genom_bayes_opt_GetBest_activity_report(
        self, (struct genom_bayes_opt_GetBest_activity *)a);
      return;
  }

  assert(!"code not reached");
}


/* --- genom_bayes_opt_activity_encodex ------------------------------------ */

int
genom_bayes_opt_activity_encodex(char *buffer, int size, char *dst, int maxsize)
{
  struct genom_activity *a = (struct genom_activity *)buffer;

  if (a->state == genom_unkex_id)
    return genom_bayes_opt_genom_unkex_encodex(a->exdetail, size, dst, maxsize);
  else if (a->state == genom_syserr_id)
    return genom_bayes_opt_genom_syserr_encodex(a->exdetail, size, dst, maxsize);
  else if (a->state == genom_incompatible_digest_id)
    return genom_bayes_opt_genom_incompatible_digest_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_bad_transition_id)
    return genom_bayes_opt_genom_bad_transition_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_interrupted_id)
    return genom_bayes_opt_genom_interrupted_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_serialization_id)
    return genom_bayes_opt_genom_serialization_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_too_many_activities_id)
    return genom_bayes_opt_genom_too_many_activities_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_disallowed_id)
    return genom_bayes_opt_genom_disallowed_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_mwerr_id)
    return genom_bayes_opt_genom_mwerr_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == bayes_opt_e_sys_id)
    return genom_bayes_opt_bayes_opt_e_sys_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_no_such_activity_id)
    return genom_bayes_opt_genom_no_such_activity_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_no_such_inport_id)
    return genom_bayes_opt_genom_no_such_inport_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_no_such_outport_id)
    return genom_bayes_opt_genom_no_such_outport_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_port_io_id)
    return genom_bayes_opt_genom_port_io_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_no_such_remote_id)
    return genom_bayes_opt_genom_no_such_remote_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_no_such_service_id)
    return genom_bayes_opt_genom_no_such_service_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == genom_remote_io_id)
    return genom_bayes_opt_genom_remote_io_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == bayes_opt_OPTIMIZATION_FAILED_id)
    return genom_bayes_opt_bayes_opt_OPTIMIZATION_FAILED_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == bayes_opt_INVALID_PARAMETER_id)
    return genom_bayes_opt_bayes_opt_INVALID_PARAMETER_encodex(
      a->exdetail, size, dst, maxsize);
  else if (a->state == bayes_opt_EVALUATION_FAILED_id)
    return genom_bayes_opt_bayes_opt_EVALUATION_FAILED_encodex(
      a->exdetail, size, dst, maxsize);

  assert(!"unknown genom exception");
  return 0;
}


