/* kill */
static __inline__ int
genom_bayes_opt_kill_interrupt_reqd(
  struct genom_component_data *self, struct genom_activity *a)
{
  int delay = 0;
  (void)self; (void)a; /* fix -Wunused-parameter */


  /* task optimize */
  pthread_mutex_lock(&self->tasks.optimize.lock);
  {
    struct genom_activity *c;
    size_t id;

    for(id = 0; id < genom_max_activities(); id++) {
      c = &self->tasks.optimize.activities.a[id].any;
      if (c->status == ACT_VOID || c->status == ACT_ETHER) continue;
      if (c->aid == a->aid) continue;
      switch(c->sid) {
        case BAYES_OPT_Init_RQSTID:
        case BAYES_OPT_AskNext_RQSTID:
        case BAYES_OPT_SubmitResult_RQSTID:
        case BAYES_OPT_GetBest_RQSTID:
          switch(c->status) {
            case ACT_RUN:
              delay = 1;
              if (!self->tasks.optimize.runnable) {
                self->tasks.optimize.runnable = 1;
                pthread_cond_broadcast(&self->tasks.optimize.sync);
              }
              /*FALLTHROUGH*/
            case ACT_INIT:
              c->stop = 1;
              c->interruptedby = "kill";
              break;

            case ACT_STOP: delay = 1; break;

            default: assert(!"code not reached");
          }
      }
    }
  }
  pthread_mutex_unlock(&self->tasks.optimize.lock);

  return delay;
}

